    for i in 0..=(n - k) {
        let j = i + k;
        let first_half_end = i + half_k;
        let second_half_start = first_half_end;
        let second_half_end = j;

        // Sum of prices in the second half of the window
        let sum_prices_second_half = prefix_prices[second_half_end] - prefix_prices[second_half_start];

        // Sum of strategy[i] * prices[i] in the entire window
        let sum_strategy_prices_window = prefix_strategy_prices[j] - prefix_strategy_prices[i];

        // The change in profit for this window
        let delta = sum_prices_second_half - sum_strategy_prices_window;
        let new_profit = original_profit + delta;

        if new_profit > max_profit {
            max_profit = new_profit;
        }
    }

    max_profit
}
